var threshold = Number(msg.payload);
if (Number.isNaN(threshold)) { return null; }
msg.topic = "controls/group_33/project33/threshold";
msg.payload = { threshold: threshold };
return msg;

// Actual temperature — plotted at the moment it was measured.
var actual = Number(msg.payload.actual_temp);
var sampleTs = Date.parse(msg.payload.timestamp || "");

// Predicted temperature — plotted at the future time it targets (predicted_for).
// With a 10 s horizon this point appears just ahead of the actual line,
// and the actual line will catch up to it within a few samples.
var predicted = msg.payload.predicted_temp;
var forecastTs = Date.parse(msg.payload.predicted_for || "");

if (!Number.isNaN(actual) && !Number.isNaN(sampleTs)) {
    node.send({ topic: "Actual", payload: actual, timestamp: sampleTs });
}

if (typeof predicted === "number" && !Number.isNaN(predicted) && !Number.isNaN(forecastTs)) {
    node.send({ topic: "Predicted", payload: predicted, timestamp: forecastTs });
}

return null;

var actual = Number(msg.payload.actual_temp);
if (Number.isNaN(actual)) { return null; }
msg.payload = actual;
return msg;

var predicted = msg.payload.predicted_temp;
if (typeof predicted !== "number" || Number.isNaN(predicted)) { return null; }
msg.payload = predicted;
return msg;

var actual      = Number(msg.payload.actual_temp);
var predicted   = (typeof msg.payload.predicted_temp === "number") ? Number(msg.payload.predicted_temp) : null;
var avg         = Number(msg.payload.window_avg);
var trend       = msg.payload.trend || "warming_up";
var threshold   = Number(msg.payload.threshold);
var horizonSec  = Number(msg.payload.prediction_horizon_sec);
var ts          = msg.payload.timestamp || "";
var forecastTs  = Date.parse(msg.payload.predicted_for || "");
var sampleTs    = Date.parse(ts);

// Anomaly counter
var anomalyCount = context.get("anomalyCount") || 0;
if (msg.payload.is_anomaly === true) {
    anomalyCount += 1;
    context.set("anomalyCount", anomalyCount);
}

// Instantaneous abs error (predicted this cycle vs actual this cycle).
// Not a true validation — just shows how far the model is from current.
var absError = null;
if (predicted !== null && !Number.isNaN(predicted) && !Number.isNaN(actual)) {
    absError = Math.abs(predicted - actual);
}

// --- Lag validation ---
// Store each forecast keyed by the future timestamp it targets.
// When an actual reading arrives whose timestamp is close to a stored
// forecast target, compare them — that is the true forecast accuracy.
//
// Tolerance: horizon is 10 s, samples arrive every 2-5 s, so we allow
// ±6 s (6000 ms) to find a matching actual for a given forecast.
var HORIZON_MS   = horizonSec * 1000;
var TOLERANCE_MS = 6000;

var pendingForecasts = context.get("pendingForecasts") || [];

// Store new forecast
if (!Number.isNaN(forecastTs) && predicted !== null && !Number.isNaN(predicted)) {
    pendingForecasts.push({ ts: forecastTs, val: predicted });
}

// Expire forecasts older than horizon + tolerance (they will never be matched)
if (!Number.isNaN(sampleTs)) {
    pendingForecasts = pendingForecasts.filter(function(item) {
        return (sampleTs - item.ts) < (HORIZON_MS + TOLERANCE_MS + 5000);
    });
}

// Try to match the current actual reading to a pending forecast
var lagValidation = null;
if (!Number.isNaN(sampleTs) && !Number.isNaN(actual) && pendingForecasts.length > 0) {
    var bestIndex = -1;
    var bestDiff  = Number.MAX_SAFE_INTEGER;
    for (var i = 0; i < pendingForecasts.length; i++) {
        var diff = Math.abs(sampleTs - pendingForecasts[i].ts);
        if (diff < bestDiff) {
            bestDiff  = diff;
            bestIndex = i;
        }
    }
    if (bestIndex >= 0 && bestDiff <= TOLERANCE_MS) {
        lagValidation = Math.abs(actual - pendingForecasts[bestIndex].val);
        pendingForecasts.splice(bestIndex, 1);
    }
}

context.set("pendingForecasts", pendingForecasts);

return [
    { payload: trend.toUpperCase() },
    { payload: Number.isNaN(avg)       ? "N/A" : avg.toFixed(2) + " degC" },
    { payload: String(anomalyCount) },
    { payload: lagValidation === null        ? "N/A" : lagValidation.toFixed(2) + " degC" },
    lagValidation === null ? null : { topic: "Forecast Error", payload: lagValidation },
    { payload: Number.isNaN(threshold) ? "N/A" : threshold.toFixed(1) + " degC" },
    { payload: ts },
    { payload: lagValidation === null   ? "N/A" : lagValidation.toFixed(2) + " degC" },
    { payload: Number.isNaN(horizonSec) ? "N/A" : Math.round(horizonSec) + " seconds ahead" }
];

var actual    = Number(msg.payload.actual_temp);
var threshold = Number(msg.payload.threshold);
if (Number.isNaN(actual) || Number.isNaN(threshold)) { return null; }
var isCritical = actual > threshold;
msg.payload = {
    status:  isCritical ? "CRITICAL" : "NORMAL",
    message: isCritical
        ? "Actual temperature " + actual.toFixed(2) + " degC exceeds threshold " + threshold.toFixed(1) + " degC"
        : "Actual temperature is within safe range."
};
return msg;

var rows      = Number(msg.payload.row_count);
var lastWrite = msg.payload.last_write;
return [
    { payload: Number.isNaN(rows) ? "N/A" : String(rows) },
    { payload: lastWrite ? String(lastWrite) : "N/A" }
];

if (!msg.payload) { msg.payload = "No export response yet"; return msg; }
if (msg.payload.status === "OK") {
    msg.payload = "Exported " + msg.payload.row_count + " rows to " + msg.payload.csv_path;
} else {
    msg.payload = "Export failed: " + (msg.payload.error || "unknown error");
}
return msg;

if (msg.payload && msg.payload.status === "CRITICAL") {
    msg.payload = msg.payload.message;
    return msg;
}
return null;
